const body = $input.first().json.body;
const message = body.entry?.[0]?.changes?.[0]?.value?.messages?.[0];

if (!message) {
  return { json: { error: 'No message found' } };
}

const phone = message.from;
const text = message.text?.body?.toLowerCase() || '';
const name = body.entry?.[0]?.changes?.[0]?.value?.contacts?.[0]?.profile?.name || 'Usuario';

return {
  json: {
    phone,
    name,
    text,
    messageId: message.id,
    timestamp: message.timestamp
  }
};

const events = $input.all().map(i => i.json);
const now = DateTime.now();

// Horario laboral: Lun-Vie 9-18hrs
const workHours = [];
for (let day = 0; day < 7; day++) {
  const date = now.plus({days: day});
  if (date.weekday >= 1 && date.weekday <= 5) {
    for (let hour = 9; hour < 18; hour++) {
      const slot = date.set({hour, minute: 0, second: 0});
      const slotEnd = slot.plus({hours: 1});

      // Check if slot is free
      const isBusy = events.some(e => {
        const start = DateTime.fromISO(e.start?.dateTime || e.start?.date);
        const end = DateTime.fromISO(e.end?.dateTime || e.end?.date);
        return slot >= start && slot < end;
      });

      if (!isBusy && slot > now) {
        workHours.push({
          datetime: slot.toISO(),
          formatted: slot.toFormat('dd/MM HH:mm'),
          day: slot.toFormat('EEEE', {locale: 'es'})
        });
      }
    }
  }
}

return {
  json: {
    availableSlots: workHours.slice(0, 5),
    phone: $('Parse WhatsApp Message').first().json.phone,
    name: $('Parse WhatsApp Message').first().json.name
  }
};
